// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;
contract Vote{
    address electionComision;
    address public winner;

    struct Voter{
        string name;
        uint age;
        uint voterId;
        string gender;
        uint voteCandidateId;
        address voterAddress;
    }

    struct Candidate{
        string name;
        string party;
        uint age;
        string gender;
        uint candidateId;
        address candidateAddress;
        uint votes;
    }

    uint nextVoterId=1;
    uint nextCandidateId=1;
    
    uint startTime;
    uint endTime;

    mapping(uint=>Voter) voterDetails;
    mapping(uint=>Candidate) candidateDetails;
    bool stopVoting;

    constructor(){
        electionComision=msg.sender;
    }

    modifier isVotingOver(){
        require(endTime>block.timestamp || stopVoting,"voting is over");
        _;
    }
    modifier onlyCommisioner(){
        require(electionComision==msg.sender,"Not from election Commision");
        _;
    }
    function candidateRegister(string calldata _name,string calldata _party,uint _age,string calldata _gender) public {
        require(msg.sender!=electionComision,"You're election commission and you can't be a candidate");
        require(candidateVarification(msg.sender)==true,"candidate alreday register");
        require(_age>=18,"you are not eligible");
        require(nextCandidateId<3,"candidate registration full");
        candidateDetails[nextCandidateId]=Candidate(_name,_party,_age,_gender,nextCandidateId,msg.sender,0);
        nextCandidateId++;
    }

    function candidateVarification(address person) internal view returns(bool){
        for(uint i=1;i<nextCandidateId;i++){
            if(candidateDetails[i].candidateAddress==person){
                return false;
            }
        }
        return true;
    }
    function candidateList() public view returns(Candidate[] memory){
        Candidate[] memory arr=new Candidate[](nextCandidateId);
        for(uint i=1;i<nextCandidateId;i++){
           arr[i-1]=candidateDetails[i];
        }
        return arr;
    }

    function voterRegister(string calldata _name,uint _age,string calldata _gender) public {
        require(_age>=18,"you are not elegible for voting");
        require(VoterVerification(msg.sender)==true,"voter already register");
        voterDetails[nextVoterId]=Voter(_name,_age,nextVoterId,_gender,0,msg.sender);
        nextVoterId++;

    }
    function VoterVerification(address _person) internal view returns(bool){
       for(uint i=1;i<nextVoterId;i++){
           if(voterDetails[i].voterAddress==_person){
               return false;
           }
       }
       return true;
    }
    function voterList() public view returns(Voter[] memory){
        Voter[] memory array=new Voter[](nextVoterId);
        for(uint i=1;i<=nextVoterId;i++){
            array[i-1]=voterDetails[i];
        }
        return array;
    }
    function vote(uint _voterId,uint _CandidateId) external  isVotingOver{
        require(voterDetails[_voterId].voteCandidateId==0, "already voted");
        require(voterDetails[_voterId].voterAddress==msg.sender,"check You VoterId or you are not registered");
        require(startTime!=0,"voting not started");
        require(nextCandidateId==3,"candidate registration has not done yet");
        require(_CandidateId>0 && _CandidateId<3,"invalid candidate Id");
        voterDetails[_voterId].voteCandidateId=_CandidateId;
        candidateDetails[_CandidateId].votes++;
    }

    function VoteTime(uint StartTime,uint EndTime)external onlyCommisioner{
        startTime=block.timestamp+StartTime;
        endTime=startTime+EndTime;
        stopVoting=false;
    }

    function voting_status() public view returns( string memory){
        if(startTime==0){
            return "voting not started";
        }
        else if(endTime<=block.timestamp && stopVoting==false && startTime!=0){
            return "voting in progress"; 
        }
        else return "voting is over";
        
    }
    function result() external onlyCommisioner() isVotingOver(){
        if(candidateDetails[1].votes>candidateDetails[2].votes){
            winner=candidateDetails[1].candidateAddress;
        }
        else {
            winner=candidateDetails[2].candidateAddress;
        }
    }

    function emergency() public onlyCommisioner(){
        stopVoting=true;

    }

}

